starter.javascript:
// roll a die: a random integer from 1 to 6, inclusive
// Math.floor(Math.random() * (6 - 1 + 1)) + 1 gives 1..6
// then, if the roll is >= 1 AND <= 6, print exactly: in range
// otherwise print exactly: out of range

reference.pseudocode:
die ← RANDOM(1, 6)
IF(die ≥ 1 AND die ≤ 6)
{
  DISPLAY("in range")
}
ELSE
{
  DISPLAY("out of range")
}

reference.python:
import random
die = random.randint(1, 6)
if die >= 1 and die <= 6:
    print("in range")
else:
    print("out of range")

reference.javascript:
let die = Math.floor(Math.random() * 6) + 1;
if (die >= 1 && die <= 6) {
  console.log("in range");
} else {
  console.log("out of range");
}

