starter.javascript:
// roll two dice, each a random integer from 1 to 6
// add them to get the total
// the smallest possible total is 1+1=2, the largest is 6+6=12
// print exactly 'valid sum' if the total is between 2 and 12, else 'bad sum'

reference.pseudocode:
d1 ← RANDOM(1, 6)
d2 ← RANDOM(1, 6)
total ← d1 + d2
IF(total ≥ 2 AND total ≤ 12)
{
  DISPLAY("valid sum")
}
ELSE
{
  DISPLAY("bad sum")
}

reference.javascript:
let d1 = Math.floor(Math.random() * 6) + 1;
let d2 = Math.floor(Math.random() * 6) + 1;
let total = d1 + d2;
if (total >= 2 && total <= 12) {
  console.log("valid sum");
} else {
  console.log("bad sum");
}

starter.javascript:
// start by assuming the die is fair
// roll a random integer from 1 to 4 one thousand times in a loop
// if any roll is < 1 or > 4, the die is not fair
// after the loop, print exactly 'all fair' or 'unfair'

reference.pseudocode:
result ← "all fair"
REPEAT 1000 TIMES
{
  roll ← RANDOM(1, 4)
  IF(roll < 1 OR roll > 4)
  {
    result ← "unfair"
  }
}
DISPLAY(result)

reference.javascript:
let result = "all fair";
for (let i = 0; i < 1000; i++) {
  let roll = Math.floor(Math.random() * 4) + 1;
  if (roll < 1 || roll > 4) {
    result = "unfair";
  }
}
console.log(result);
